mapper.select:
        SELECT DATE_FORMAT(create_time,'%Y-%m') AS thisMonth,SUM(amount) income FROM app_wxpay_order
       	WHERE user_id = #{userId}
	    GROUP BY thisMonth;

        SELECT DATE_FORMAT(create_time,'%Y-%m') AS thisMonth,SUM(amount) income FROM app_wxpay_order
       	WHERE user_id = #{userId} AND DATE_FORMAT(create_time,'%Y%m') = #{date}
	    GROUP BY thisMonth;

SELECT id,partner_trade_no partnerTradeNo,concat('-',amount)amount,create_time,concat('余额提现')workName
    FROM app_wx_cash_out_record
    WHERE user_id = #{userId} and DATE_FORMAT(create_time,'%Y-%m') = #{thisMonth}
